external_knowledge:
- 'Legendary Pokémon' refers to rare and powerful Pokémon in the Pokémon universe;
- 'Super effective against' means the type has a strong advantage over another type in battles;
- 'Pokedex number' is a unique identifier for each Pokémon in the Pokémon database.

- 'Delved deepest' refers to the user with the highest total access count;
- 'Peered into the secrets' refers to the view count and edit count;
- 'Average wisdom' refers to the average base experience points of the Pokémon forms;
- 'Ancient scrolls' and 'ancient texts' refer to the Pokémon data and access logs.

sql:
SELECT pokedex_number, MAX(base_experience) AS max_base_experience, MAX(capture_rate) AS max_capture_rate
FROM legendaries
GROUP BY pokedex_number;

SELECT MAX(form_count) AS max_forms_in_habitat
FROM (
    SELECT habitat, COUNT(form_id) AS form_count
    FROM forms
    GROUP BY habitat
) AS habitat_counts;

SELECT COUNT(*) AS total_forms
FROM forms
WHERE base_experience > (SELECT AVG(base_experience) FROM forms);

SELECT pokedex_number 
FROM mythicals 
WHERE base_experience > (
  SELECT AVG(base_experience) 
  FROM forms
);

